<?php $v=function($k,$a=null)use($item){return isset($item[$k])?$item[$k]:($a&&isset($item[$a])?$item[$a]:'');};?><section class="page-heading"><h1><?=!empty($item['id'])?'Editar lançamento':'Novo lançamento'?></h1></section><?php if($errors):?><div class="alert"><?=e(implode(' ',array_values($errors)))?></div><?php endif;?><form method="post" class="editor-form"><input type="hidden" name="_csrf_token" value="<?=e(Auth::csrfToken())?>"><label>Indicador<input name="indicadorId" value="<?=e($v('indicadorId'))?>" required></label><label>Ano<input type="number" name="ano" value="<?=e($v('ano'))?>" required></label><label>Mês<input type="number" min="1" max="12" name="mes" value="<?=e($v('mes'))?>" required></label><label>Plano<input name="plano" value="<?=e($v('plano'))?>"></label><label>Pilar<input name="pilar" value="<?=e($v('pilar'))?>"></label><label>Unidade apuradora<input name="unidadeApuradora" value="<?=e($v('unidadeApuradora'))?>" required></label><label>Diretoria responsável<input name="diretoriaResponsavel" value="<?=e($v('diretoriaResponsavel'))?>"></label><label class="full-span">Observação<textarea name="observacaoArea"><?=e($v('observacaoArea'))?></textarea></label><?php if(isset($item['status'])&&LancamentoStateMachine::normalize($item['status'])==='Reaberto'):?><label class="full-span">Justificativa da retificação<textarea name="justificativaRetificacao" required></textarea></label><?php endif;?><button>Salvar rascunho</button></form>
